import { Router } from 'express';
import { authenticate, requireRole } from '../middleware/auth.js';
import { validateBody } from '../middleware/validate.js';
import { createGuestRecord, getGuestRecords } from '../controllers/guestController.js';
import { getSubmissionStatus, submitMonth } from '../controllers/submissionController.js';
import { businessDashboard } from '../controllers/analyticsController.js';
import { getInbox, markAsRead } from '../controllers/messagesController.js';
import { guestRecordSchema } from '../validations/guest.js';
import { submitMonthSchema } from '../validations/submission.js';
const router = Router();
router.use(authenticate, requireRole('business'));
router.get('/dashboard', businessDashboard);
router.get('/guest-records', getGuestRecords);
router.post('/guest-records', validateBody(guestRecordSchema), createGuestRecord);
router.get('/submissions', getSubmissionStatus);
router.post('/submissions', validateBody(submitMonthSchema), submitMonth);
router.get('/messages', getInbox);
router.patch('/messages/:id/read', markAsRead);
export default router;
